  ('disabled-c5fb3965-moex-00341', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-110-d1a761c9', 'sub-disabled-c5fb3965-02', NULL, 'single_choice', '依訴願法之規定，下列何者非屬應為不受理決定之情形？', '["訴願書不合法定程式且不能補正", "行政處分於訴願審議期間已經原處分機關撤銷", "訴願人對於已經決定之訴願事件重行提起訴願", "行政處分所憑理由不當，但依其他理由認為正當者"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:57+00:00", "source_pdf_sha1": "6e41655acede", "answer_pdf_sha1": "bbcc6f9a3cef", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "402", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL),
  ('disabled-c5fb3965-moex-00342', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-110-d1a761c9', 'sub-disabled-c5fb3965-02', NULL, 'single_choice', '關於訴願法上訴願程序之敘述，下列何者正確？', '["訴願人不服受理訴願機關於訴願程序中所為之程序上處置者，得聲明異議", "訴願人撤回訴願者，非經訴願管轄機關之同意，不得再提起同一之訴願", "原行政處分涉及地方自治團體之地方自治事務者，受理訴願之上級機關 僅得就其適當性進行審查決定", "原處分機關於訴願駁回決定確定後發現原處分錯誤，如不損害訴願人權 益，得撤銷原處分而另為新處分"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:57+00:00", "source_pdf_sha1": "6e41655acede", "answer_pdf_sha1": "bbcc6f9a3cef", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "402", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 41, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL),
  ('disabled-c5fb3965-moex-00343', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-110-d1a761c9', 'sub-disabled-c5fb3965-02', NULL, 'single_choice', '依行政法院實務見解，受理訴願機關因訴願有理由而撤銷原處分後，下列 敘述何者正確？', '["原處分機關重為處分時，原則上不得於相對人表示不服之範圍內更為不 利益之處分", "原處分非因裁量違法而為有利於相對人之裁量者，原處分機關即不得為 更不利之裁量", "於發回原處分機關另為處分時，受理訴願機關應指定相當期間命其為 之，但不得超過1個月", "基於對原處分機關法定職權之尊重，受理訴願機關不得對原處分作成逕 為變更之決定"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:57+00:00", "source_pdf_sha1": "6e41655acede", "answer_pdf_sha1": "bbcc6f9a3cef", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "402", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 42, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL),
  ('disabled-c5fb3965-moex-00344', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-110-d1a761c9', 'sub-disabled-c5fb3965-02', NULL, 'single_choice', '有關行政訴訟之意涵與審判權範圍之敘述，下列何者正確？', '["行政訴訟之意旨在確保國家立法權之合法行使，增進行政功能為宗旨", "一切公法上之爭議皆應依行政訴訟法提起訴訟", "行政訴訟僅係對抽象規範爭議之解決", "交通裁決事件由地方法院行政訴訟庭審理"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:57+00:00", "source_pdf_sha1": "6e41655acede", "answer_pdf_sha1": "bbcc6f9a3cef", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "402", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 43, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL),
  ('disabled-c5fb3965-moex-00345', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-110-d1a761c9', 'sub-disabled-c5fb3965-02', NULL, 'single_choice', '依據司法院大法官解釋意旨，法律雖係為公共利益或一般國民福祉而設之 規定，但就法律之整體結構、適用對象、所欲產生之下列何項效果及社會 發展因素等綜合判斷，可得知亦有保障特定人之意旨時，則個人主張其權 益因公務員怠於執行職務而受損害者，下列敘述何者正確？', '["僅得提起刑事救濟", "得提起國家賠償", "得請求損失補償", "係屬反射利益不得救濟"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:57+00:00", "source_pdf_sha1": "6e41655acede", "answer_pdf_sha1": "bbcc6f9a3cef", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "402", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 44, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL),
